module top_module(
    input clk,
    input reset,
    input [31:0] in,
    output reg [31:0] out
);reg [31:0] cnt;

always @(posedge clk, posedge reset) begin
    if (reset) begin
        cnt <= 0;
        out <= 0;
    end
    else begin
        cnt <= cnt + 1;
        if (in < cnt) begin
            out <= 1;
        end
    end
end

endmodule
